const httpRequest = (options) => this.helpers.httpRequest(options);
async function requestJson(options, label) {
  let lastError;
  for (let attempt = 1; attempt <= 5; attempt++) {
    try {
      const response = await httpRequest({ ...options, json: true, simple: false, resolveWithFullResponse: true, timeout: options.timeout || 120000 });
      const statusCode = response.statusCode || response.status || 200;
      const body = response.body ?? response;
      if (statusCode < 200 || statusCode >= 300) throw new Error(label + ' HTTP ' + statusCode + ': ' + JSON.stringify(body).slice(0, 1000));
      return body;
    } catch (error) {
      lastError = error;
      const message = String(error?.message || error || '');
      const responseBody = error?.response?.body || error?.response?.data || {};
      const responseText = JSON.stringify(responseBody);
      const transient = responseBody?.code === 1254607
        || responseText.includes('1254607')
        || message.includes('1254607')
        || message.includes('Client network socket disconnected')
        || message.includes('socket hang up')
        || message.includes('ECONNRESET')
        || message.includes('ETIMEDOUT')
        || message.includes('EAI_AGAIN')
        || message.includes('HTTP 500')
        || message.includes('HTTP 502')
        || message.includes('HTTP 503')
        || message.includes('HTTP 504');
      if (!transient || attempt >= 5) throw error;
      await sleep(1500 * attempt);
    }
  }
  throw lastError;
}
async function feishuToken() {
  const res = await requestJson({ method: 'POST', url: 'https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal', headers: { 'Content-Type': 'application/json' }, body: { app_id: FEISHU_APP_ID, app_secret: FEISHU_APP_SECRET } }, '飞书取 token');
  return res.tenant_access_token;
}
async function getRecord(token, tableId, recordId) {
  try {
    const res = await requestJson({ method: 'GET', url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records/' + recordId, headers: { Authorization: 'Bearer ' + token } }, '飞书读记录');
    return res?.data?.record;
  } catch (error) {
    const records = await listRecords(token, tableId, 200);
    const fallback = records.find((record) => record.record_id === recordId);
    if (fallback) return fallback;
    throw error;
  }
}
async function listRecords(token, tableId, pageSize = 200) {
  const res = await requestJson({ method: 'GET', url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records?page_size=' + pageSize, headers: { Authorization: 'Bearer ' + token } }, '飞书列记录');
  return res?.data?.items || [];
}
async function updateRecord(token, tableId, recordId, fields) {
  await requestJson({ method: 'PUT', url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records/' + recordId, headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json; charset=utf-8' }, body: { fields } }, '飞书更新记录');
}
async function createRecord(token, tableId, fields) {
  const res = await requestJson({ method: 'POST', url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records', headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json; charset=utf-8' }, body: { fields } }, '飞书创建记录');
  const id = res?.data?.record?.record_id;
  if (!id) throw new Error('飞书创建记录无 record_id: ' + JSON.stringify(res).slice(0, 800));
  return id;
}
async function sleep(ms) { return new Promise((resolve) => setTimeout(resolve, ms)); }
function firstSelect(value) { return Array.isArray(value) ? String(value[0]?.text || value[0]?.name || value[0] || '') : String(value || ''); }
function textCell(value) { if (Array.isArray(value)) return value.map((x) => x?.text || x?.name || x).join(''); if (value && typeof value === 'object') return value.text || value.link || ''; return String(value || ''); }
function urlCell(value) { if (Array.isArray(value)) return value[0]?.link || value[0]?.text || ''; if (value && typeof value === 'object') return value.link || value.text || ''; return String(value || ''); }
function linkIds(value) { return Array.isArray(value) ? value.map((x) => x?.record_id || x?.id || x?.record_ids?.[0] || x).filter(Boolean) : []; }
function urlValue(url) { return url ? { text: url, link: url } : null; }
function parseJson(input) {
  if (input && typeof input === 'object' && !input.text && !input.output) return input;
  const raw = String(input?.text || input?.output || input?.response || '');
  const cleaned = raw.replace(/^\s*\`\`\`(?:json)?/i, '').replace(/\`\`\`\s*$/i, '').trim();
  try { return JSON.parse(cleaned); } catch {}
  const first = cleaned.indexOf('{'); const last = cleaned.lastIndexOf('}');
  if (first >= 0 && last > first) return JSON.parse(cleaned.slice(first, last + 1));
  throw new Error('无法解析 JSON: ' + cleaned.slice(0, 500));
}
